import { useMarkets } from "@/lib/query/hooks";
import { useAssumptions } from "./AssumptionContext";
import { AssumptionBar } from "./AssumptionBar";
import { VariableRow } from "./VariableRow";
import type { Market } from "@/lib/api/types";

interface AssumptionPanelProps {
  market: Market;
}

export function AssumptionPanel({ market }: AssumptionPanelProps) {
  const { data: marketsData } = useMarkets();
  const { assumptions } = useAssumptions();

  const allMarkets = marketsData?.markets ?? [];
  const activeMarkets = allMarkets.filter((m) => m.status === "active");

  // Show current market first, then others
  const sortedIds = [
    market.id,
    ...activeMarkets.filter((m) => m.id !== market.id).map((m) => m.id),
  ];

  return (
    <div style={panelStyle}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "var(--space-sm)" }}>
        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
          Variables & Assumptions
        </h3>
        <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
          {assumptions.length > 0
            ? `Showing conditionals given ${assumptions.length} assumption${assumptions.length > 1 ? "s" : ""}`
            : "Showing marginal probabilities"}
        </span>
      </div>

      <AssumptionBar />

      <div style={{ display: "grid", gap: "var(--space-sm)", marginTop: "var(--space-sm)" }}>
        {sortedIds.map((id) => (
          <VariableRow key={id} marketId={id} targetMarket={market} />
        ))}
      </div>

      {activeMarkets.length <= 1 && (
        <div style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-md)" }}>
          Create more markets to use assumptions — assumptions let you condition on other variables.
        </div>
      )}
    </div>
  );
}

const panelStyle: React.CSSProperties = {
  padding: "var(--space-md)",
  borderRadius: "var(--radius-md)",
  border: "1px solid var(--color-border)",
  background: "var(--color-bg-surface)",
};

import { useAssumptions } from "./AssumptionContext";

export function AssumptionBar() {
  const { assumptions, removeAssumption, clearAll } = useAssumptions();

  if (assumptions.length === 0) return null;

  return (
    <div style={barStyle}>
      <span style={{ fontSize: "0.75rem", fontWeight: 600, color: "var(--color-text-muted)", marginRight: 8 }}>
        GIVEN:
      </span>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, flex: 1 }}>
        {assumptions.map((a) => (
          <span key={a.variableId} style={tagStyle}>
            {a.label} = {a.outcomeId}
            <button
              onClick={() => removeAssumption(a.variableId)}
              style={tagCloseStyle}
              aria-label={`Remove assumption ${a.label}`}
            >
              ×
            </button>
          </span>
        ))}
      </div>
      <button onClick={clearAll} style={clearBtnStyle}>
        Clear all
      </button>
    </div>
  );
}

const barStyle: React.CSSProperties = {
  display: "flex",
  alignItems: "center",
  padding: "8px 12px",
  borderRadius: "var(--radius-md)",
  background: "rgba(59, 130, 246, 0.08)",
  border: "1px solid rgba(59, 130, 246, 0.25)",
  gap: 8,
};

const tagStyle: React.CSSProperties = {
  display: "inline-flex",
  alignItems: "center",
  gap: 4,
  padding: "2px 8px",
  borderRadius: 4,
  background: "var(--color-primary)",
  color: "#fff",
  fontSize: "0.75rem",
  fontWeight: 600,
};

const tagCloseStyle: React.CSSProperties = {
  background: "none",
  border: "none",
  color: "rgba(255,255,255,0.7)",
  cursor: "pointer",
  fontSize: "0.85rem",
  padding: "0 2px",
  lineHeight: 1,
};

const clearBtnStyle: React.CSSProperties = {
  background: "none",
  border: "none",
  color: "var(--color-primary)",
  cursor: "pointer",
  fontSize: "0.75rem",
  fontWeight: 500,
  whiteSpace: "nowrap",
};

